    <script>
        const SUPABASE_URL = 'https://xvldfsmxskhemkslsbym.supabase.co';
        const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...'; // Replace with yours
        const refinery = window.supabase.createClient(SUPABASE_URL, SUPABASE_KEY);

        async function fetchStats() {
            try {
                document.getElementById('last-updated').innerText = 'Neural Sync...';
                const { data, error } = await refinery.functions.invoke('refinery-dashboard');
                if (error) throw error;

                // Update Global Header
                document.getElementById('total-unique').innerText = data.global.total_unique_words.toLocaleString();
                document.getElementById('total-duplicates').innerText = data.global.total_duplicates.toLocaleString();
                document.getElementById('key-count').innerText = `${data.global.api_keys_active} Nodes Active`;
                document.getElementById('cooldown-text').innerText = `${data.global.api_keys_in_cooldown} Nodes in Cooldown`;

                // Update Yield Table (The SQL Result)
                tbody.innerHTML = data.file_breakdown.map(f => `
                    <tr onclick="inspectFile('${f.source}', ${f.source.includes('chunk')})" class="hover:bg-white/5 active:bg-sky-500/10 transition-colors cursor-pointer">
                        <td class="p-4 font-medium text-slate-300 sticky left-0 bg-[#0f172ae6] backdrop-blur-md z-10 border-r border-white/5">
                            ${f.source}
                            <div class="w-16 h-1 bg-white/5 rounded-full mt-1">
                                <div class="h-full bg-sky-500 rounded-full" style="width: ${f.progress_percent}%"></div>
                            </div>
                        </td>
                        <td class="p-4 text-right font-mono whitespace-nowrap">
                           <span class="text-emerald-400">${f.completed_batches}</span><span class="text-slate-600">/${f.total_batches}</span>
                        </td>
                        <td class="p-4 text-right text-slate-500 font-mono whitespace-nowrap">${f.last_index?.toLocaleString() || 0}</td>
                        <td class="p-4 text-right font-bold text-white whitespace-nowrap">${f.unique_words.toLocaleString()}</td>
                    </tr>
                `).join('');

                // Update Queue Stats
                const q = data.script2_queue.stats;
                const totalQ = data.script2_queue.total_chunks;
                const queueDiv = document.getElementById('queue-stats');
                queueDiv.innerHTML = `
                    ${renderBar('Completed', q.completed, totalQ, 'bg-emerald-500')}
                    ${renderBar('Processing', q.processing, totalQ, 'bg-sky-500')}
                    ${renderBar('Failed', q.failed, totalQ, 'bg-rose-500')}
                    ${renderBar('Pending', q.pending, totalQ, 'bg-slate-700')}
                `;

                // Update Logs
                const logList = document.getElementById('view-logs');
                logList.innerHTML = data.errors.recent_logs.map(log => `
                    <div class="glass-card p-4 rounded-xl border-l-2 border-rose-500/50">
                        <div class="flex justify-between text-[9px] mb-2">
                            <span class="text-rose-400 font-bold uppercase">${log.error_type}</span>
                            <span class="text-slate-500">${new Date(log.created_at).toLocaleTimeString()}</span>
                        </div>
                        <p class="text-[11px] text-slate-300 leading-snug">${log.error_message}</p>
                    </div>
                `).join('');

                document.getElementById('last-updated').innerText = `Synced: ${new Date().toLocaleTimeString()}`;
            } catch (err) {
                document.getElementById('last-updated').innerText = 'Sync Error';
            }
        }

        async function inspectFile(source, isScript2) {
            const panel = document.getElementById('deep-stats-panel');
            panel.classList.remove('hidden');
            panel.scrollIntoView({ behavior: 'smooth' });

            document.getElementById('inspect-title').innerText = source.toUpperCase();

            // Note: Manual string building for search params to ensure Deno receives them
            try {
                const funcUrl = `refinery-dashboard?file=${encodeURIComponent(source)}&is_script2=${isScript2}`;
                const { data, error } = await refinery.functions.invoke(funcUrl);
                if (error) throw error;

                document.getElementById('stat-total-words').innerText = data.total_words.toLocaleString();
                document.getElementById('stat-unique-roots').innerText = data.unique_roots.toLocaleString();
                document.getElementById('stat-success-rate').innerText = `${data.success_rate}%`;
                document.getElementById('stat-health').innerText = data.health;

                const posColors = { Noun: 'bg-sky-500', Verb: 'bg-emerald-500', Adjective: 'bg-amber-500', Adverb: 'bg-rose-500' };
                const posBar = document.getElementById('pos-bar');
                const posLegend = document.getElementById('pos-legend');
                posBar.innerHTML = ''; posLegend.innerHTML = '';

                Object.entries(data.pos_distribution).forEach(([pos, count]) => {
                    const pct = (count / data.total_words) * 100;
                    const color = posColors[pos] || 'bg-slate-500';
                    posBar.innerHTML += `<div class="${color} h-full" style="width: ${pct}%"></div>`;
                    posLegend.innerHTML += `<div class="flex justify-between"><span>${pos}</span><span class="text-slate-500">${Math.round(pct)}%</span></div>`;
                });

                document.getElementById('root-cloud').innerHTML = data.top_roots.map(r => `
                    <div class="px-2 py-1 bg-white/5 rounded-lg text-[11px] font-amharic">
                        ${r.root} <span class="text-[9px] text-slate-500 ml-1">${r.count}</span>
                    </div>
                `).join('');

            } catch (err) { console.error(err); }
        }

        function renderBar(label, count, total, color) {
            const pct = total > 0 ? (count / total) * 100 : 0;
            return `
                <div>
                    <div class="flex justify-between text-[10px] mb-1 uppercase font-bold tracking-widest">
                        <span class="text-slate-500">${label}</span>
                        <span>${count}</span>
                    </div>
                    <div class="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                        <div class="${color} h-full transition-all duration-1000" style="width: ${pct}%"></div>
                    </div>
                </div>`;
        }

        function switchTab(tab) {
            ['breakdown', 'queue', 'logs'].forEach(t => {
                document.getElementById(`view-${t}`).classList.add('hidden');
                document.getElementById(`tab-${t}`).classList.remove('tab-active');
            });
            document.getElementById(`view-${tab}`).classList.remove('hidden');
            document.getElementById(`tab-${tab}`).classList.add('tab-active');
        }

        function closeInspector() { document.getElementById('deep-stats-panel').classList.add('hidden'); }

        fetchStats();
        setInterval(fetchStats, 60000);
    </script>
</body>
